sql:
SELECT h.hospital_name, r.region_name
FROM hospitals h
JOIN regions r ON h.region_id = r.region_id;

SELECT hospital_name, total_beds
FROM hospitals
WHERE total_beds > (SELECT AVG(total_beds) FROM hospitals);
